async (params, browser) => {
  // Open dataset page
  await browser.open(`https://www.kaggle.com/datasets/${params.dataset_slug}`)

  // Wait for dataset page
  await browser.waitForSelector('h1, [role=\'main\']', 15000)

  // Let page render
  await browser.wait(3000)

  // Scroll for more content
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract dataset info
  const dataset_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim() || document.title.split('|')[0]?.trim() || ''; const descEl = document.querySelector('[class*="markdown"], [class*="description"], [class*="rendered"]'); const desc = descEl ? descEl.textContent.trim().substring(0, 1000) : ''; const files = []; document.querySelectorAll('a[href*="?select="], tr td:first-child, [class*="file"] span').forEach(f => { const text = f.textContent?.trim(); if (text && text.length < 100 && text.length > 1) files.push(text); }); const allText = document.body.innerText; const usabilityMatch = allText.match(/(\d+\.?\d*)\s*(?:usability|score)/i); const downloadMatch = allText.match(/(\d[\d,]*)\s*downloads?/i); const sizeMatch = allText.match(/(\d+\.?\d*\s*(?:KB|MB|GB|TB))/i); const tags = []; document.querySelectorAll('a[href*="/tags/"]').forEach(a => { const text = a.textContent.trim(); if (text && text.length < 50) tags.push(text); }); return { title, description: desc, files: files.slice(0, 20), usability: usabilityMatch ? usabilityMatch[1] : '', downloads: downloadMatch ? downloadMatch[1] : '', size: sizeMatch ? sizeMatch[1] : '', tags: tags.slice(0, 10), url: window.location.href };`)

  return dataset_data
}
